// ── Public API ────────────────────────────────────────────────────────────────

export async function fetchGridStatus() {
  try {
    return await apiFetch('/api/grid-status');
  } catch {
    console.warn('[api] /api/grid-status unreachable — using mock data');
    return MOCK_GRID;
