      '[NEGOTIATED] 400 MW WB → BHR @ ₹6.20/MW ✓',
      'BatteryPhase complete.',
      '[DONE] Simulation exited with code 0',
    ];
    for (const line of fakeLines) {
      await new Promise((r) => setTimeout(r, 200 + Math.random() * 150));
      onLine(line);
    }
    return { status: 'ok' };
  }
}
